// --- Types & Constants ---

type Rarity = 'Común' | 'Poco común' | 'Raro' | 'Legendario' | 'Pseudo-legendario' | 'Singular (Mítico)' | 'Ultraente' | 'Pokémon Paradoja';

export type StatusCondition = 'None' | 'Burn' | 'Sleep' | 'Poison' | 'Paralysis' | 'Freeze';

interface Move {
  name: string;
  type: string;
  power: number;
  accuracy: number;
  level_learned_at?: number;
  category?: 'Physical' | 'Special' | 'Status';
  statusEffect?: StatusCondition;
  statusChance?: number;
}

export interface PokemonBase {
  id: number;
  name: string;
  types: string[];
  ability: string;
  evolutionChain: number[]; // Array of IDs in order: [Bulbasaur, Ivysaur, Venusaur]
  isLegendary?: boolean;
  isMythical?: boolean;
  rarity?: string;
  megaId?: number;
  megaIdX?: number;
  megaIdY?: number;
  baseStatsSum?: number;
  description?: string;
  stats?: { hp: number, atk: number, def: number, spe: number };
  evolutionCondition?: {
    type: 'happiness' | 'stone' | 'item' | 'trade' | 'time';
    value?: string | number;
  };
  evolutions?: {
    id: number;
    condition: {
      type: 'level' | 'happiness' | 'stone' | 'item' | 'trade' | 'time';
      value?: string | number;
    }
  }[];
}

export interface PokemonCard extends PokemonBase {
  instanceId: string;
  rarity: Rarity;
  level: number;
  maxLevel: number;
  evolutionLevel?: number | null;
  powerLevel: number; // Max 10
  trainingLevel: number; // Max 10
  limitBroken: boolean;
  atk: number;
  def: number;
  spe: number;
  hp: number;
  maxHp: number;
  ovr: number;
  status?: StatusCondition;
  isEvolved: boolean;
  isShiny: boolean;
  sprite?: string;
  fatigue: number; // 0-100
  moral: number; // 0-100
  happiness: number; // 0-255
  isInjured: boolean;
  injuryWeeks: number;
  matchesPlayed: number;
  mvpCount: number;
  totalDamageDealt: number;
  matchHistory: {
    opponent: string;
    result: 'win' | 'loss' | 'draw';
    damageDealt: number;
    fainted: boolean;
    date: string;
  }[];
  item?: string;
  megaStone?: string;
  megaEvolved?: boolean;
  moves: Move[];
  nature: string;
  ivs: { atk: number, def: number, spe: number, hp: number };
  evs: { atk: number, def: number, spe: number, hp: number };
}

interface Facility {
  id: string;
  name: string;
  level: number;
  maxLevel: number;
  cost: number;
  description: string;
}

interface StaffMember {
  id: string;
  name: string;
  role: 'Tactician' | 'Physio' | 'Scout';
  hired: boolean;
  cost: number;
  description: string;
}

interface Sponsor {
  id: string;
  name: string;
  description: string;
  goal: string;
  reward: { coins?: number, stardust?: number, tp?: number };
  targetValue: number;
  currentValue: number;
  isCompleted: boolean;
}

type MissionType = 'daily' | 'weekly' | 'event' | 'league';

interface Mission {
  id: string;
  title: string;
  description: string;
  goal: number;
  current: number;
  reward: { coins?: number, stardust?: number, tp?: number, banditas?: number };
  type: MissionType;
  claimed: boolean;
}

interface GameEvent {
  id: string;
  title: string;
  description: string;
  icon: string; // Emoji or Lucide icon name
  color: string;
  modifiers: {
    shinyRate?: number;
    legendaryRate?: number;
    coinMultiplier?: number;
    stardustMultiplier?: number;
    tpMultiplier?: number;
    energyRegenMultiplier?: number;
    typeBoost?: { type: string, boost: number };
    evolutionDiscount?: number;
  };
  endDate: number; // timestamp
}

interface Item {
  id: string;
  name: string;
  description: string;
  effect: { atk?: number, def?: number, spe?: number, hp?: number };
  rarity: Rarity;
}

interface MarketOffer {
  id: string;
  pokemon: PokemonCard;
  cost: number;
  seller: string;
}

